window.SmartRisk=window.SmartRisk||{};(function(){const SR=SmartRisk;let selectedId="GYE";let filtered=[...SR.MockData.territories];function summary(){const totalCantones=filtered.reduce((a,b)=>a+b.cantones,0),totalPlanes=filtered.reduce((a,b)=>a+b.planes,0),avg=Math.round(filtered.reduce((a,b)=>a+b.avance,0)/Math.max(filtered.length,1)),high=filtered.filter(x=>x.prioridad==="Alta").length;return `<section class="territory-summary"><article class="territory-summary-card"><span>Provincias visibles</span><strong>${filtered.length}</strong><small class="muted">Cobertura filtrada</small></article><article class="territory-summary-card"><span>Cantones</span><strong>${totalCantones}</strong><small class="muted">Total registrado</small></article><article class="territory-summary-card"><span>Planes</span><strong>${totalPlanes}</strong><small class="muted">En seguimiento</small></article><article class="territory-summary-card"><span>Avance promedio</span><strong>${avg}%</strong><small class="muted">${high} territorios de prioridad alta</small></article></section>`}function map(){return `<div class="territory-map"><div class="map-grid"></div><div class="map-title"><strong>Mapa esquemático Zona 5</strong><div class="muted">Seleccione una provincia</div></div>${filtered.map(t=>`<button class="province-node province-${t.id==="GYE"?"guayas":t.id==="LRI"?"losrios":t.id==="STE"?"santaelena":t.id==="BOL"?"bolivar":"galapagos"} ${selectedId===t.id?"is-selected":""}" data-province="${t.id}">${t.provincia}<small>${t.avance}%</small></button>`).join("")}</div>`}function detail(){const t=SR.MockData.territories.find(x=>x.id===selectedId)||filtered[0];if(!t)return '<div class="muted">Sin territorio seleccionado.</div>';return `<div class="territory-detail"><div><span class="kicker">Provincia seleccionada</span><h2 class="page-title" style="font-size:1.7rem">${t.provincia}</h2><p class="muted">${t.capital}</p></div><div class="detail-row"><span>Cantones</span><strong>${t.cantones}</strong></div><div class="detail-row"><span>Planes</span><strong>${t.planes}</strong></div><div class="detail-row"><span>Avance</span><strong>${t.avance}%</strong></div><div class="detail-row"><span>Prioridad</span><strong>${t.prioridad}</strong></div><div class="detail-row"><span>Población referencial</span><strong>${t.poblacion}</strong></div><div class="detail-row"><span>Responsable</span><strong>${t.coordinador}</strong></div><div><strong>Cantones destacados</strong><div class="cantons-list" style="margin-top:10px">${t.cantonesLista.map(c=>`<span class="canton-chip">${c}</span>`).join("")}</div></div></div>`}function render(){return `<section class="page-header"><div><span class="kicker">Módulo funcional</span><h1 class="page-title">Territorios</h1><p class="page-subtitle">Consulta, filtra y revisa el avance territorial de la Zona 5.</p></div><div class="split-actions">${SR.Button.render({id:"export-territories",label:"Exportar CSV",variant:"secondary",icon:"download"})}${SR.Button.render({id:"territory-help",label:"Ayuda",icon:"document"})}</div></section><div id="territory-summary-root">${summary()}</div><section class="panel" style="margin-bottom:20px"><div class="panel-body"><div class="filter-grid"><div class="search-wrap"><span class="search-icon">${SR.Icon.render("search",18)}</span><input id="territory-search" class="search-input" type="search" placeholder="Buscar provincia o capital…"></div><select id="territory-status" class="select-input"><option value="">Todos los estados</option><option value="Seguimiento">Seguimiento</option><option value="Ajustes">Ajustes</option></select><select id="territory-priority" class="select-input"><option value="">Todas las prioridades</option><option value="Alta">Alta</option><option value="Media">Media</option><option value="Especial">Especial</option></select><button id="territory-reset" class="btn btn-secondary" type="button">Limpiar</button></div><div id="territory-table"></div></div></section><section class="territory-layout">${map()}${SR.Card.panel({title:"Detalle territorial",body:`<div id="territory-detail-root">${detail()}</div>`})}</section>`}function applyFilters(){const q=SR.Utils.normalizeText(document.getElementById("territory-search").value),s=document.getElementById("territory-status").value,p=document.getElementById("territory-priority").value;filtered=SR.MockData.territories.filter(t=>SR.Utils.normalizeText(`${t.provincia} ${t.capital}`).includes(q)&&(!s||t.estado===s)&&(!p||t.prioridad===p));if(!filtered.some(t=>t.id===selectedId))selectedId=filtered[0]?.id||"";document.getElementById("territory-summary-root").innerHTML=summary();const layout=document.querySelector(".territory-layout");layout.innerHTML=`${map()}${SR.Card.panel({title:"Detalle territorial",body:`<div id="territory-detail-root">${detail()}</div>`})}`;bindMap();buildTable()}function buildTable(){const root=document.getElementById("territory-table");root.innerHTML="";SR.Table.create({containerId:"territory-table",columns:[{key:"provincia",label:"Provincia"},{key:"capital",label:"Capital"},{key:"cantones",label:"Cantones"},{key:"planes",label:"Planes"},{key:"avance",label:"Avance",type:"percent"},{key:"estado",label:"Estado",type:"status"},{key:"id",label:"Detalle",type:"action"}],rows:filtered,onAction:id=>{selectedId=id;document.getElementById("territory-detail-root").innerHTML=detail();document.querySelectorAll(".province-node").forEach(n=>n.classList.toggle("is-selected",n.dataset.province===id));document.querySelector(".territory-layout").scrollIntoView({behavior:"smooth",block:"start"})}})}function bindMap(){document.querySelectorAll("[data-province]").forEach(b=>b.onclick=()=>{selectedId=b.dataset.province;document.getElementById("territory-detail-root").innerHTML=detail();document.querySelectorAll(".province-node").forEach(n=>n.classList.toggle("is-selected",n.dataset.province===selectedId))})}function bind(){buildTable();bindMap();["territory-search","territory-status","territory-priority"].forEach(id=>document.getElementById(id).addEventListener(id==="territory-search"?"input":"change",applyFilters));document.getElementById("territory-reset").onclick=()=>{document.getElementById("territory-search").value="";document.getElementById("territory-status").value="";document.getElementById("territory-priority").value="";applyFilters()};document.getElementById("export-territories").onclick=()=>{SR.Utils.downloadCsv("territorios-zona5.csv",filtered);SR.Toast.show("Archivo CSV generado.","success")};document.getElementById("territory-help").onclick=()=>SR.Modal.open({title:"Uso del módulo Territorios",body:"<p>Utilice los filtros para reducir la vista, seleccione provincias en el mapa o en la tabla y exporte los resultados visibles a CSV.</p>",confirmLabel:"Entendido"})}SR.TerritoriosModule={route:{path:"/territorios",title:"Territorios",render,bind}}})();